import { useEffect, useState } from "react";
import { Search } from "../components/Search";
import { Songs } from "../components/Songs";
import { Player } from "../components/Player";
import { useSongs } from "../hooks/useSongs";
import { SkeletonCard } from "../components/SkeletonCard";
import { useFavorites } from "../hooks/useFavorites";

export const SearchPage = () => {
  const { songs, loading, error, search, loadMore, hasMore } =
    useSongs("Latest Songs");
  const [flag, setFlag] = useState(false);
  const [song, setPlayerSong] = useState(null);
  const { toggle, isFav } = useFavorites();

  useEffect(() => {
    search("Latest Songs");
  }, []);

  const togglePlayer = (flag, songarg) => {
    setPlayerSong(songarg);
    setFlag(flag);
  };

  const getArtistName = (artistName) => {
    search(artistName);
  };

  return (
    <div className="container">
      <h1 className="title">Music Store</h1>
      {flag ? (
        <Player fn={togglePlayer} song={song} />
      ) : (
        <>
          <Search fn={getArtistName} />

          {loading && (
            <div className="SongListDisplay">
              {Array.from({ length: 8 }).map((_, i) => (
                <SkeletonCard key={i} />
              ))}
            </div>
          )}

          {error && <p className="error-msg">{error}</p>}

          {!loading && !error && (
            <Songs
              fn={togglePlayer}
              allsongs={songs}
              isFav={isFav}
              onFav={toggle}
            />
          )}

          {/* Load More — only shown when there are more songs AND not currently loading */}
          {hasMore && !loading && (
            <button className="load-more-btn" onClick={loadMore}>
              Load More Songs
            </button>
          )}
        </>
      )}
    </div>
  );
};
